module chacha_simple (  
    input wire [31:0] key,  
    input wire [31:0] nonce,  
    input wire [31:0] obf_block_index,  
    output reg [31:0] keystream  
);  
    always @(key, nonce, obf_block_index) begin  
        keystream = (key + nonce + obf_block_index) % 32'hFFFFFFFF;  
    end  
endmodule
